// Expert Amp Server base URL
// Change this to match your installation (e.g. http://192.168.1.100:8088)
const baseUrl = 'http://localhost:8088';
flow.set('expertAmpBaseUrl', baseUrl);
flow.set('wsConnected', false);
flow.set('statusTransport', 'startup');
flow.set('usbOk', false);
msg.payload = 'expertAmpBaseUrl=' + baseUrl;
return msg;

let status = msg.payload;
if (Buffer.isBuffer(status)) {
  status = status.toString();
}
if (typeof status === 'string') {
  try {
    status = JSON.parse(status);
  } catch (err) {
    flow.set('usbOk', false);
    flow.set('statusTransport', 'error');
    node.error('invalid websocket status payload', msg);
    return null;
  }
}
if (!status || typeof status !== 'object' || Array.isArray(status)) {
  flow.set('usbOk', false);
  flow.set('statusTransport', 'error');
  node.error('unexpected websocket status payload', msg);
  return null;
}
flow.set('wsConnected', true);
flow.set('statusTransport', 'ws');
flow.set('usbOk', true);
msg.baseUrl = flow.get('expertAmpBaseUrl') || 'http://localhost:8088';
msg.transport = 'ws';
msg.payload = { success: true, data: status };
return msg;

const status = msg.status || {};
const event = String(status.event || '').toLowerCase();
const text = String(status.text || '').toLowerCase();
const connected = event === 'connect' || text.includes('connected');
if (connected) {
  flow.set('wsConnected', true);
  flow.set('statusTransport', 'ws');
  flow.set('usbOk', true);
  return [{ payload: { label: 'WS<br/>Live', background: 'linear-gradient(180deg, green, green)' } }, null];
}
flow.set('wsConnected', false);
flow.set('statusTransport', 'http-fallback');
flow.set('usbOk', false);
return [
  { payload: { label: 'HTTP<br/>Fallback', background: 'linear-gradient(180deg, orange, orange)' } },
  { payload: Date.now() }
];

const wsConnected = flow.get('wsConnected') === true;
if (wsConnected) {
  return null;
}
const base = flow.get('expertAmpBaseUrl') || 'http://localhost:8088';
msg.url = base + '/api/v1/status';
msg.method = 'GET';
msg.baseUrl = base;
msg.transport = 'http-fallback';
return msg;

const envelope = msg.payload || {};
if (!envelope.success) {
  flow.set('usbOk', false);
  flow.set('statusTransport', 'error');
  node.error(envelope.error || 'status failed', msg);
  return null;
}
const status = envelope.data || {};
const transport = msg.transport || flow.get('statusTransport') || 'http-fallback';
const wsConnected = flow.get('wsConnected') === true;
if (transport === 'ws') {
  flow.set('wsConnected', true);
  flow.set('statusTransport', 'ws');
  flow.set('usbOk', true);
} else if (!wsConnected) {
  flow.set('statusTransport', 'http-fallback');
  flow.set('usbOk', true);
}
const base = msg.baseUrl || flow.get('expertAmpBaseUrl') || 'http://localhost:8088';

const txBool = status.tx;
const rxTxBg = txBool === true ? 'linear-gradient(180deg, red, yellow)' : 'linear-gradient(180deg, green, green)';
const rxTxLabel = txBool === true ? 'TRANSMIT' : 'RECEIVE';

const opState = status.operatingState || '';
const modeVal = (opState || '').toLowerCase().includes('operat') ? 'Operate' : (opState || 'Standby');
const modeBg  = modeVal === 'Operate' ? 'linear-gradient(180deg, red, red)' : 'linear-gradient(180deg, green, green)';

const pwr = String(status.outputLevel || '').trim().toUpperCase();
let pwrLabel = status.outputLevel || '—';
let pwrBg = 'linear-gradient(180deg, gray, gray)';
if (pwr === 'L' || pwr === 'LOW') {
  pwrLabel = 'Low';
  pwrBg = modeVal === 'Operate' ? 'linear-gradient(180deg, purple, purple)' : 'linear-gradient(180deg, green, green)';
} else if (pwr === 'M' || pwr === 'MED' || pwr === 'MID' || pwr === 'MIDDLE') {
  pwrLabel = 'Middle';
  pwrBg = modeVal === 'Operate' ? 'linear-gradient(180deg, red, purple)' : 'linear-gradient(180deg, green, green)';
} else if (pwr === 'H' || pwr === 'HIGH' || pwr === 'MAX' || pwr === 'MAXIMUM') {
  pwrLabel = 'Maximum';
  pwrBg = modeVal === 'Operate' ? 'linear-gradient(180deg, red, red)' : 'linear-gradient(180deg, green, green)';
}

const bandVal = String(status.bandText || status.band || status.bandCode || '').trim();
const bandLabel = bandVal ? 'Band<br/>' + bandVal : 'Band<br/>—';
const rxAntVal = status.rxAntenna || status.antenna || '';
const rxAntLabel = rxAntVal ? 'RX Ant ' + rxAntVal + (status.antennaBank ? '<br/>Bank ' + status.antennaBank : '') : 'RX Ant —';
const modelLabel = status.modelName ? String(status.modelName).replace(/ /g, '<br/>') : 'Model<br/>—';
const inputLabel = status.input ? 'Input ' + status.input : 'Input —';
const antLabel = status.antenna ? 'Ant ' + status.antenna + (status.antennaBank ? '<br/>Bank ' + status.antennaBank : '') : 'Ant —';
const bankVal = String(status.antennaBank || '').trim();
const bankLabel = bankVal ? 'Bank ' + bankVal : 'Bank —';

const warnings = Array.isArray(status.warningsText) ? status.warningsText : (Array.isArray(status.warnings) ? status.warnings : []);
const alarms = Array.isArray(status.alarmsText) ? status.alarmsText : (Array.isArray(status.activeAlarms) ? status.activeAlarms : []);
const warningsLabel = warnings.length ? ('Warnings<br/>' + warnings.join('<br/>')) : 'No Warnings';
const warningsBg = warnings.length ? 'linear-gradient(180deg, orange, orange)' : 'linear-gradient(180deg, blue, blue)';
const alarmsLabel = alarms.length ? ('Alarms<br/>' + alarms.join('<br/>')) : 'No Alarms';
const alarmsBg = alarms.length ? 'linear-gradient(180deg, red, red)' : 'linear-gradient(180deg, blue, blue)';

const statusTransport = flow.get('statusTransport') || transport;
let usbLbl = 'HTTP<br/>Error';
let usbBg = 'linear-gradient(180deg, red, red)';
if (statusTransport === 'ws' && flow.get('usbOk') !== false) {
  usbLbl = 'WS<br/>Live';
  usbBg = 'linear-gradient(180deg, green, green)';
} else if (statusTransport === 'http-fallback' && flow.get('usbOk') !== false) {
  usbLbl = 'HTTP<br/>Fallback';
  usbBg = 'linear-gradient(180deg, orange, orange)';
} else if (statusTransport === 'manual-http' && flow.get('usbOk') !== false) {
  usbLbl = wsConnected ? 'WS<br/>Live' : 'HTTP<br/>Fallback';
  usbBg = wsConnected ? 'linear-gradient(180deg, green, green)' : 'linear-gradient(180deg, orange, orange)';
}
const syncBg = 'linear-gradient(180deg, blue, blue)';
const syncLbl = 'USB<br/>Sync';

return [
  { label: modelLabel, background: 'linear-gradient(180deg, blue, blue)' },
  { label: rxTxLabel, background: rxTxBg },
  { label: modeVal, background: modeBg },
  { label: pwrLabel, background: pwrBg },
  { label: antLabel, background: 'linear-gradient(180deg, green, green)' },
  { label: inputLabel, background: 'linear-gradient(180deg, blue, blue)' },
  { label: bandLabel, background: 'linear-gradient(180deg, blue, blue)' },
  { label: rxAntLabel, background: 'linear-gradient(180deg, blue, blue)' },
  { label: usbLbl, background: usbBg },
  { label: syncLbl, background: syncBg },
  null,
  Object.assign({}, msg, { status: status }),
  { label: bankLabel, background: 'linear-gradient(180deg, blue, blue)' },
  { label: warningsLabel, background: warningsBg },
  { label: alarmsLabel, background: alarmsBg }
];

const status = msg.status || {};
const atuSwr = status.swr !== undefined && status.swr !== null ? Number(status.swr) : null;
const antSwr = atuSwr;
const pwrW   = status.powerWatts !== undefined ? Number(status.powerWatts) : null;
const pwrPct = pwrW !== null ? Math.min(100, Math.round(pwrW / 15)) : null;

const atuMsg = atuSwr !== null ? {payload: atuSwr} : null;
const antMsg = antSwr !== null ? {payload: antSwr} : null;
const pwrMsg = pwrPct !== null ? {payload: pwrPct} : null;

return [atuMsg, antMsg, pwrMsg];

const base = flow.get('expertAmpBaseUrl') || 'http://localhost:8088';
msg.url    = base + '/api/v1/alarms';
msg.method = 'GET';
return msg;

const envelope = msg.payload || {};
const data     = (envelope.data || {});
const active   = Array.isArray(data.active) ? data.active : [];
const hasWarn  = active.some(s => /warn/i.test(s));
const hasAlarm = active.length > 0 && !hasWarn;

const warnBg  = hasWarn  ? 'linear-gradient(180deg, orange, orange)' : 'linear-gradient(180deg, blue, blue)';
const alarmBg = hasAlarm ? 'linear-gradient(180deg, red, red)'       : 'linear-gradient(180deg, blue, blue)';
const warnLbl = hasWarn  ? 'Warnings<br/>' + active.filter(s=>/warn/i.test(s))[0] : 'No Warnings';
const alarmLbl= hasAlarm ? 'Alarms<br/>' + active[0] : 'No Alarms';

return [
  { label: warnLbl,  background: warnBg  },
  { label: alarmLbl, background: alarmBg }
];

// USB Sync: triggers immediate HTTP status refresh
const base = flow.get('expertAmpBaseUrl') || 'http://localhost:8088';
msg.url = base + '/api/v1/status';
msg.method = 'GET';
msg.baseUrl = base;
msg.transport = 'manual-http';
return msg;

const raw = msg.payload;
let name;
if (typeof raw === 'string') {
  name = raw;
} else if (raw && typeof raw === 'object') {
  name = raw.payload || raw.action || raw.name || msg.topic;
} else {
  name = msg.topic;
}
name = String(name || '').trim().toLowerCase();

const buttonActions = ['set','left','right','up','down','display','input','antenna',
                       'band-','band+','l-','l+','c-','c+','tune','off','power','operate','cat'];
const base = flow.get('expertAmpBaseUrl') || 'http://localhost:8088';
msg.method  = 'POST';
msg.headers = {'Content-Type': 'application/json'};
msg.topic   = name;

if (name === 'wake') {
  msg.url = base + '/api/v1/actions/wake';
  msg.payload = null;
  return msg;
}

if (!buttonActions.includes(name)) {
  node.warn('blocked or unsupported action: ' + JSON.stringify(raw));
  return null;
}
msg.url     = base + '/api/v1/actions/button';
msg.payload = {name: name};
return msg;

const env  = msg.payload || {};
const ok   = env.success !== false;
const name = (env.data && env.data.name) ? env.data.name : (msg.topic || '?');
msg.payload = ok ? 'OK: ' + name : 'FAIL: ' + name + ' (' + (env.error || '?') + ')';
return msg;

flow.set('usbOk', false);
flow.set('statusTransport', 'error');
msg.payload = { label: 'HTTP<br/>Error', background: 'linear-gradient(180deg, red, red)' };
return msg;

let event = msg.payload;
if (Buffer.isBuffer(event)) {
  event = event.toString();
}
const isStartupKick = typeof event === 'number' || event === '' || event == null;
if (typeof event === 'string' && !isStartupKick) {
  try {
    event = JSON.parse(event);
  } catch (err) {
    node.error('invalid display websocket payload', msg);
    return null;
  }
}
if (isStartupKick) {
  event = { startup: true };
}
if (!event || typeof event !== 'object' || Array.isArray(event)) {
  node.error('unexpected display websocket payload', msg);
  return null;
}
const seq = Number(event.sequence || 0);
const lastSeq = Number(flow.get('lastDisplaySequence') || 0);
if (!event.startup && seq > 0 && seq === lastSeq) {
  return null;
}
if (seq > 0) {
  flow.set('lastDisplaySequence', seq);
}
const base = flow.get('expertAmpBaseUrl') || 'http://localhost:8088';
const nonce = encodeURIComponent(String(seq > 0 ? seq : Date.now()));
msg.renderPngFresh = base + '/api/v1/display/render.png?t=' + nonce;
msg.renderPng = base + '/api/v1/display/render.png';
msg.renderSvg = base + '/api/v1/display/render.svg';
msg.payload = event;
return msg;
